  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);
```

---

### 3. 🔒 No Request Body Parsing Limits
If you ever add `POST`/`PUT` routes, unguarded body parsing can lead to payload attacks:
```js
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));
```

